export const SEED_DRILLS = [

  // ── PASSING (15) ──────────────────────────────────────────────────────────
  { id:1,  title:"Rondo Passing Circle",         category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"8-12",               home_ready:false, diagram:"rondo",    description:"Players form a circle with 2 defenders in the middle. Outside players keep possession using quick one and two-touch passes. Defenders try to intercept. Rotate defenders every 90 seconds.", coach_notes:"Emphasise eye contact before the pass. Encourage movement after passing — don't stand still." , progression:"Reduce the circle size to increase pressure. Add a third defender. Limit to one touch only." },
  { id:2,  title:"Wall Passes",                  category:"Passing", age_groups:["U12","U13","U14"], duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"wall",     description:"Have your child pass the ball against a wall and control the rebound. Vary the distance and angle of the passes to work on both short and long passes. Try to use both feet equally.", coach_notes:"Vary the weight and angle each session. Encourage players to control with their weaker foot too." , progression:"Increase the distance from the wall. Add a second touch — control then pass. Use weaker foot only." },
  { id:3,  title:"Triangle Passing",             category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"6-9",                home_ready:false, diagram:"triangle", description:"3 players stand in a triangle 8m apart. Pass and move to a different point each time. Progression: add a defender in the middle.", coach_notes:"Encourage open body shape — receive across the body so you can see the next pass before it arrives." , progression:"Reduce to one touch. Add two defenders in the middle. Increase triangle size and add movement." },
  { id:4,  title:"Target Passing",               category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"gates",    description:"Set up targets such as small goals or markers at various distances around the garden. Challenge your child to pass the ball accurately to hit each target — accuracy over power.", coach_notes:"Encourage players to record how many out of 10 they hit and try to beat their score next time." , progression:"Increase distance between targets. Add a defender who tries to intercept. Use weaker foot only." },
  { id:5,  title:"4-Goal Possession",            category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"10-14",              home_ready:false, diagram:"4goal",    description:"4v4 in a 25x25m grid with 4 small goals. Teams score by passing through any goal. Encourages switching play and scanning.", coach_notes:"Praise players who switch play quickly. Stop the game to show what opening up looks like." , progression:"Add a rule that players must complete 5 passes before scoring. Reduce grid size." },
  { id:6,  title:"One-Touch Passing Line",       category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"8+",                 home_ready:false, diagram:"line",     description:"Two lines face each other 6m apart. Player passes, then runs to the back of the opposite line. One touch only. Build pace over time.", coach_notes:"Feet ready before the ball arrives. First touch mindset — get the body behind the ball early." , progression:"Increase pace — no standing still. Add a defender in the middle to intercept." },
  { id:7,  title:"Switch & Drive",               category:"Passing", age_groups:["U13","U14"],       duration:"10 min", players:"8-12",               home_ready:false, diagram:"switch",   description:"In a 40m wide channel, players must switch the ball across the pitch in 3 passes or fewer before a player drives forward.", coach_notes:"Builds width awareness. Praise players who look for the switch even under pressure." , progression:"Add a time limit — must switch in 2 passes. Add a pressing defender." },
  { id:8,  title:"Passing Square",               category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"4-8",                home_ready:false, diagram:"square",   description:"4 cones form a 10x10m square. Players rotate passing clockwise then anti-clockwise. Vary pace and add a directional change on coach signal.", coach_notes:"Encourage body orientation — don't always face the same direction. Scan before receiving." , progression:"One touch only. Add directional instructions — player must pass in the direction called by coach." },
  { id:9,  title:"Blind Side Pass",              category:"Passing", age_groups:["U13","U14"],       duration:"10 min", players:"6-10",               home_ready:false, diagram:"blind",    description:"Attackers use a decoy run to create a blind side, then play a layoff pass to a runner. Defenders attempt to track. Rotate roles every 3 minutes.", coach_notes:"The communication before the pass is as important as the pass itself. Verbal cue first." , progression:"Add an active defender who tries to intercept the layoff. Reduce the space available." },
  { id:10, title:"Progressive Passing Lanes",    category:"Passing", age_groups:["U12","U13","U14"], duration:"10 min", players:"8-14",               home_ready:false, diagram:"lanes",    description:"Divide the pitch into 3 vertical lanes. Team must pass into each lane before shooting. Builds progressive build-up play.", coach_notes:"Reward patience. Teams that rush into shooting without using all 3 lanes restart possession." , progression:"Add a time limit per zone. Introduce a defender in each lane." },
  { id:11, title:"Combination Play — Give & Go", category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"6-10",               home_ready:false, diagram:"give&go",    description:"Player passes to a teammate and immediately sprints to receive it back in a new position. Work in groups of 3 across a 20m channel. Rotate roles every 5 reps.", coach_notes:"The sprint after the pass is the skill — many players stand and watch. Reward the run." , progression:"Add light contact. Progress to full 1v1 with a goal to defend." },
  { id:12, title:"Long Diagonal Switching",      category:"Passing", age_groups:["U13","U14","U15"], duration:"10 min", players:"8-14",               home_ready:false, diagram:"switch",   description:"Full width pitch setup. Players work in pairs on opposite flanks switching the ball diagonally across the pitch using driven passes. Must land within 2m of partner.", coach_notes:"Technique focus — locked ankle, follow through toward the target. Don't sacrifice accuracy for power." , progression:"Reduce the channel width. Add a second attacker so defender must choose who to track." },
  { id:13, title:"Receive & Turn",               category:"Passing", age_groups:["U12","U13","U14"], duration:"10 min", players:"Pairs",              home_ready:false, diagram:"triangle", description:"Player A plays a firm pass to Player B who has their back to goal. Player B must control and turn in one movement before playing the ball through a gate. Rotate every 8 reps.", coach_notes:"Half turn on receiving — open body before the ball arrives. This is a key U12-U14 skill." , progression:"Add a second defender. Reduce box size to increase pressure." },
  { id:14, title:"3v1 Keep Ball",                category:"Passing", age_groups:["U12","U13"],       duration:"10 min", players:"8-12",               home_ready:false, diagram:"rondo",    description:"3 attackers keep the ball from 1 defender in an 8x8m square. 10 consecutive passes = 1 point. Defender rotates on interception or after 30 seconds.", coach_notes:"Quick feet, quick decisions. Encourage support angles — never stand behind the ball." , progression:"Reduce the time to win the ball to 7 seconds. Add a fourth attacker." },
  { id:15, title:"Passing Under Pressure",       category:"Passing", age_groups:["U12","U13","U14"], duration:"10 min", players:"6-10",               home_ready:false, diagram:"gates",    description:"Pairs pass through 5 gates in a 20x20m area while 2 defenders try to intercept. Score 1 point per gate. Swap defenders every 2 minutes.", coach_notes:"Decision-making under pressure. Encourage quick scanning before receiving — know your next pass before the ball arrives." , progression:"Progress to moving shadow — both players jogging. Then add light contact." },

  // ── TACKLING & DEFENDING (15) ─────────────────────────────────────────────
  { id:16, title:"Shadow Tackle Drill",          category:"Tackling", age_groups:["U12","U13"],       duration:"10 min", players:"Pairs",             home_ready:false, diagram:"tackle",     description:"Players work in pairs. One dribbles slowly, the other mirrors their movement practising stance and timing without contact. Progress to controlled contact on coach signal.", coach_notes:"Correct body shape first — side-on approach, low stance, eyes on ball not player." , progression:"Shorten the head start. Add a second attacker to create a 2v1 after the sprint." },
  { id:17, title:"Jockeying Channel",            category:"Tackling", age_groups:["U12","U13"],       duration:"10 min", players:"Pairs",             home_ready:false, diagram:"jockey",     description:"Set a 5m wide, 15m long channel. Attacker dribbles to end line; defender jockeys without tackling for first 10m, then can attempt to win the ball.", coach_notes:"Goal is to delay, not win the ball immediately. Patience is the skill — reward defenders who stay on their feet." , progression:"Add a second attacking unit pressing at the same time. Introduce specific press triggers." },
  { id:18, title:"1v1 Tackle Box",               category:"Tackling", age_groups:["U12","U13"],       duration:"10 min", players:"Pairs",             home_ready:false, diagram:"1v1box",     description:"8x8m box. Attacker attempts to dribble out any side; defender attempts a clean tackle. Swap every 60 seconds. First to 5 wins.", coach_notes:"Tackle timing: wait for the attacker's heavy touch. Don't commit early — patience wins." , progression:"Progress to live 1v1 situations. Introduce timing — only slide when opponent takes heavy touch." },
  { id:19, title:"Press & Win",                  category:"Tackling", age_groups:["U12","U13","U14"], duration:"10 min", players:"6-10",              home_ready:false, diagram:"press",      description:"3 attackers play out from the back; 3 defenders press as a unit to win the ball within 10 seconds. Reset and repeat.", coach_notes:"The trigger to press is key. Agree on the signal before the drill starts — a back pass or goalkeeper touch." , progression:"Increase the number of attackers to 3v2. Add a time limit to force quicker decisions." },
  { id:20, title:"Channelling to Safety",        category:"Tackling", age_groups:["U12","U13"],       duration:"10 min", players:"Pairs",             home_ready:false, diagram:"channel",    description:"Defender steers attacker toward the touchline using body shape alone — no tackle. Attacker tries to cut back inside. Switch roles every 90 seconds.", coach_notes:"Arms out, stay patient, guide them wide. Reward defenders who succeed without diving in." , progression:"Add light contact. Progress to full 1v1 where defender can attempt a tackle." },
  { id:21, title:"Recovery Run & Defend",        category:"Tackling", age_groups:["U13","U14"],       duration:"10 min", players:"Pairs",             home_ready:false, diagram:"recovery",   description:"Defender starts 5m behind attacker. On signal, both sprint 20m. Defender must recover and use body shape to delay — no wild lunge.", coach_notes:"Recover to the inside of the attacker, not directly at the ball. Control the angle, don't dive in." , progression:"Remove the pass requirement — attackers can shoot immediately. Reduce to 3v3." },
  { id:22, title:"Team Defensive Shape",         category:"Tackling", age_groups:["U13","U14","U15"], duration:"10 min", players:"Full squad",        home_ready:false, diagram:"defshape",   description:"Full defensive unit pressed by an attacking team. Coach freeze-coaches to correct shape, compactness, and press triggers.", coach_notes:"Pause when shape is poor, ask players to identify the problem before you correct it." , progression:"Introduce a second defender. Vary the cross height — driven, lofted, pulled back." },
  { id:23, title:"Intercept or Hold",            category:"Tackling", age_groups:["U12","U13"],       duration:"10 min", players:"6-10",              home_ready:false, diagram:"intercept",  description:"Midfield scenario: 2 attackers + goalkeeper vs 2 defenders. Defenders decide whether to intercept the pass or hold their line. Discuss choices after each rep.", coach_notes:"No right answer every time — the decision-making is the skill. Reward the right choice, not just the successful one." , progression:"Reduce the channel width. Give the defender a head start from behind." },
  { id:24, title:"Defensive Line Work",          category:"Tackling", age_groups:["U13","U14","U15"], duration:"10 min", players:"Full squad",        home_ready:false, diagram:"defshape",   description:"Back 4 practise holding a defensive line — stepping up together on coach signal, dropping on signal. Introduce offside trap once movement is coordinated.", coach_notes:"Communication is everything — nominate a leader to call the line. Everyone moves on the same voice." , progression:"Reduce the number of attackers to 3v2. Add a time limit of 8 seconds." },
  { id:25, title:"2v2 Defending",                category:"Tackling", age_groups:["U12","U13"],       duration:"10 min", players:"8-12",              home_ready:false, diagram:"2v2",     description:"2v2 in a 15x10m channel. Defenders work together to win the ball — one applies pressure, one covers. Rotate pairs every 2 minutes.", coach_notes:"The covering defender's angle is key — not too close, not too far. They should be able to see both the ball and their attacker." , progression:"Add a second defender who tracks the overlapping run. Vary the timing of the overlap." },
  { id:26, title:"Press Triggers Training",      category:"Tackling", age_groups:["U13","U14","U15"], duration:"10 min", players:"Full squad",        home_ready:false, diagram:"press",      description:"Walk through 3 pre-agreed press triggers as a team (back pass, poor first touch, sideways pass). Practise recognising the trigger and pressing as a unit.", coach_notes:"Slow walk-through first. The whole team must agree on the trigger — if one player doesn't press, the shape breaks." , progression:"Reduce the time limit to 1.5 seconds. Add a second defender closing from a different angle." },
  { id:27, title:"Tackle Timing Gates",          category:"Tackling", age_groups:["U12","U13","U14"], duration:"10 min", players:"Pairs",             home_ready:false, diagram:"channel",    description:"Attacker dribbles through a 10m channel toward a gate. Defender must choose the right moment to attempt a tackle — too early or too late and the attacker scores.", coach_notes:"Teach patience — the correct moment is when the attacker takes a heavy touch. Count the successes not the attempts." , progression:"Make both defenders active from the start. Add a time limit for the combination." },
  { id:28, title:"Compact Defending Shape",      category:"Tackling", age_groups:["U13","U14","U15"], duration:"10 min", players:"Full squad",        home_ready:false, diagram:"defshape",   description:"Team practises staying compact defensively — two banks maintaining 15m between lines. Ball moved around by attackers; team shifts as a unit.", coach_notes:"Show visually what compact looks like vs a stretched team. Use cones to mark the ideal distances between lines." , progression:"Increase the pace of the service. Mix in aerial balls that require a headed or chested first touch." },
  { id:29, title:"Slide Tackle Technique",       category:"Tackling", age_groups:["U13","U14"],       duration:"10 min", players:"Any",               home_ready:false, diagram:"slide",      description:"Soft ground only. Players practise sliding on their non-dominant hip, leading with the stronger foot. Technique must be clean before adding any opposition.", coach_notes:"Only at U13+. Emphasise it's a last resort — show examples of poorly timed slide tackles as a deterrent." , progression:"Make both defenders active immediately. Add a second defender tracking the run." },
  { id:30, title:"Goalkeeper Distribution",      category:"Tackling", age_groups:["U12","U13","U14"], duration:"10 min", players:"Any",               home_ready:false, diagram:"gk",         description:"Goalkeeper practises distribution from hands and ground. Throw to target players in wide areas, then driven passes on the ground. Defenders must retreat 10 yards — retreat line rule applies.", coach_notes:"At U12/13 the retreat line means opposition must be 10 yards away. Encourage the GK to look up before distributing — don't just boot it." , progression:"Add active defenders to the set piece. Vary the delivery point — near post, far post, short." },

  // ── ATTACKING & FINISHING (15) ────────────────────────────────────────────
  { id:31, title:"3v2 Attacking Overload",       category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"10-15",             home_ready:false, diagram:"3v2",        description:"3 attackers vs 2 defenders + goalkeeper in a 20x15m grid. Must complete 3 passes before shooting. Rotate roles every 5 minutes.", coach_notes:"Encourage the third man run. The player without the ball should always be creating space." , progression:"Reduce cone spacing to 0.5m. Add a ball — dribble through the cones instead of running." },
  { id:32, title:"Finishing From Crosses",       category:"Attacking", age_groups:["U12","U13","U14"], duration:"10 min", players:"6-12",              home_ready:false, diagram:"cross",       description:"Wide player delivers from the flank. 2 attackers make near and far post runs. Vary the delivery — early, pulled back, driven.", coach_notes:"Run timing is more important than finish quality at this age. Reward well-timed runs even if the finish is poor." , progression:"Increase speed between sets. Add a ball — dribble out of each gate rather than just passing." },
  { id:33, title:"Spot Shooting",                category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"Solo or with a parent",home_ready:true, diagram:"shootpress",   description:"Mark different spots around your garden. Take shots from each spot aiming for a specific part of the goal or target. Improves shooting accuracy from different angles and distances. Score yourself out of 10 per spot.", coach_notes:"Vary where they aim — corners not just the middle. Encourage players to track their scores and beat them next session." , progression:"Reduce the coach's arm-drop signal — use a smaller movement to make the reaction harder." },
  { id:34, title:"Counter Attack Sprint",        category:"Attacking", age_groups:["U12","U13","U14"], duration:"10 min", players:"8-14",              home_ready:false, diagram:"counter",     description:"4 attackers start in their own half. On signal, sprint forward in a 4v2. Defenders start 5m ahead of goal. Must score within 10 seconds.", coach_notes:"Speed of thought, not just legs. Decide quickly who shoots, who makes the distracting run." , progression:"Increase box height to 40cm. Add a lateral jump — jump to side platform then back." },
  { id:35, title:"Overlapping Run Drill",        category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"6-10",              home_ready:false, diagram:"overlap",     description:"Full back overlaps winger on the outside. Winger holds until the overlap is on, then lays off into space. Drill both sides equally.", coach_notes:"Communication is everything — 'on your shoulder' triggers the overlap. Drill the call as much as the movement." , progression:"Reduce rest time to 10 seconds. Add a medicine ball for the plank and glute bridge." },
  { id:36, title:"Shooting Under Pressure",      category:"Attacking", age_groups:["U12","U13","U14"], duration:"10 min", players:"Any",               home_ready:false, diagram:"shootpress",  description:"Player receives 20m from goal with a defender closing from 10m. Must decide to shoot, turn, or lay off within 2 seconds.", coach_notes:"Make the time pressure real — loud 3-second countdown. Reward the right decision, not just the goals." , progression:"Introduce partner races through the same gates. Add a ball — dribble through the gates." },
  { id:37, title:"Combination Play into Box",    category:"Attacking", age_groups:["U13","U14"],       duration:"10 min", players:"6-10",              home_ready:false, diagram:"combo",       description:"3 players combine using one-twos and layoffs to work ball into penalty area and finish. Passive defender becomes active on entry to box.", coach_notes:"Reward fluency. Walk through the pattern at zero speed if players lose shape." , progression:"Reduce the sprint distance to the halfway line only — more sprints, less recovery." },
  { id:38, title:"First Touch & Finish",         category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"Solo or with a parent",home_ready:true, diagram:"firsttouch", description:"A parent serves the ball at varying heights and pace. Player controls with one touch then shoots in two touches max. Solo version: kick against a wall at an angle and react to the rebound.", coach_notes:"First touch direction is the skill — coach where the touch goes, not just that it's controlled." , progression:"Add resistance bands for leg swings and lunges. Increase reps on each movement." },
  { id:39, title:"Wide Attack Patterns",         category:"Attacking", age_groups:["U13","U14","U15"], duration:"10 min", players:"8-12",              home_ready:false, diagram:"wideattack",  description:"Pull-back, early cross, cut inside — attackers run rehearsed patterns from wide areas. Passive defender becomes active once pattern is learned.", coach_notes:"Walk through at zero speed first. Only add defenders once the shapes are familiar." , progression:"Increase speed challenge — set a target number of taps per 30 seconds to beat." },
  { id:40, title:"Set Piece Attack",             category:"Attacking", age_groups:["U13","U14","U15"], duration:"10 min", players:"Full squad",        home_ready:false, diagram:"setpiece",    description:"Practise 2 corner and 1 free kick routine. Near post flick, far post run, short corner. Every player has an assigned role.", coach_notes:"Every player should know exactly where to stand and where to run — no guessing. Repetition is key." , progression:"Add a ball — juggle while walking forward. Set a personal best target to beat each session." },
  { id:41, title:"1v1 Dribble & Finish",         category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"Pairs",             home_ready:false, diagram:"dribble",     description:"Attacker starts with the ball and must beat a defender in a 10x15m channel before shooting. 60-second bouts. Celebrate clever feints even if they don't beat the player.", coach_notes:"Encourage variety of moves — not just pace. Show players 2-3 moves they can practise (stepover, cut inside, drag back)." , progression:"Introduce a passive defender who adds light pressure. Add a second ball." },
  { id:42, title:"Third Man Run",                category:"Attacking", age_groups:["U13","U14","U15"], duration:"10 min", players:"9-12",              home_ready:false, diagram:"thirdman",       description:"Player A passes to Player B. Player B lays off to Player C who has made a timed run in behind. Focus is entirely on the timing of the third man's movement.", coach_notes:"The third man runs when the ball goes to Player B — not before, not after. This takes repetition. Use cones to mark the run angle." , progression:"Introduce a time limit to switch from 9v9 to 7v7 during the same session." },
  { id:43, title:"2v1 Overload Attack",          category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"9-12",              home_ready:false, diagram:"2v1",         description:"2 attackers vs 1 defender to goal. Attackers must use the overload — pass to create the shooting chance. Defender scores a point for every clearance.", coach_notes:"The player without the ball must move to create the passing angle. If they stand still, the defender can cover both." , progression:"Introduce a pressed defender who adds light pressure to the shape." },
  { id:44, title:"Dribble Through Gates",        category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"Any",               home_ready:false, diagram:"weave",       description:"Set 8 gates (pairs of cones) randomly in a 20x20m area. Players dribble through as many gates as possible in 60 seconds. Record score and beat it.", coach_notes:"Head up while dribbling — players must scan for the next gate before they get to it. This is the key coaching point." , progression:"Add moving players — walk through offside scenarios at jogging pace with active defenders." },
  { id:45, title:"Attacking Shape — 9v9",        category:"Attacking", age_groups:["U12","U13"],       duration:"10 min", players:"Full squad",        home_ready:false, diagram:"positions",   description:"Full squad practise shape in possession for 9v9 — wide players pushed high, two central midfielders supporting the striker. Coach feeds ball in and freezes to correct positions.", coach_notes:"Two key questions: are the wide players wide enough? Are the midfielders at the right depth? Freeze and correct before players move." , progression:"Add a second pressing unit. Introduce a time limit — press must win ball within 6 seconds." },

  // ── STRENGTH & CONDITIONING (10) ──────────────────────────────────────────
  { id:46, title:"Cone Dribbling",               category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"weave",       description:"Set up cones in a straight line — bottles or jumpers work just as well. Dribble through focusing on close control using both feet. Start slow, then build speed. Try 5 runs.", coach_notes:"Encourage inside and outside of each foot — not just one. Parents can time runs and challenge their child to beat their time." , progression:"Add set piece variations — two corner routines and one free kick added to the session." },
  { id:47, title:"Figure Eight Dribbling",       category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"ladder",      description:"Place two cones about 5 yards apart. Dribble in a figure-eight pattern to focus on changing direction quickly and using both feet. 10 eights, rest 30 seconds, repeat 3 times.", coach_notes:"Only needs 2 cones or bottles. The figure eight naturally forces both feet if done correctly." , progression:"Introduce in-game analysis — pause and ask players to identify shape breakdowns themselves." },
  { id:48, title:"Core Circuit",                 category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"core",        description:"No equipment needed. 40 seconds on, 20 seconds rest: Plank, Side plank left, Side plank right, Glute bridge, Dead bug. Rest 1 minute, repeat 3 rounds.", coach_notes:"Technique over duration. A 20-second perfect plank beats a 60-second sagging one." , progression:"Move to 11v11 friendly fixtures from March as per FAW guidance." },
  { id:49, title:"Dynamic Warm-Up Routine",      category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"warmup",      description:"Jog on the spot 1 min, then: high knees (30s), heel kicks (30s), leg swings (10 each leg), hip circles (10 each direction), reverse lunge with twist (5 each side). All dynamic — no holding stretches.", coach_notes:"Run this before every home session. The routine becomes a mental warm-up cue over time." , progression:"Run the session with the U13 squad to expose U12 players to faster pace." },
  { id:50, title:"Toe Taps",                     category:"Strength & Conditioning", age_groups:["U12","U13"],       duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"ballmastery", description:"Stand over the ball and tap lightly with alternating feet. Start slow, build speed. 30 seconds on, 15 seconds rest for 5 rounds. Count taps and try to beat your score.", coach_notes:"Watch for players leaning back. They should be balanced slightly forward over the ball." , progression:"Introduce split leadership — different captains for different phases of play." },
  { id:51, title:"Ball Juggling",                category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"10 min", players:"Solo or with a parent",home_ready:true,  diagram:"shuttle",     description:"Juggle using feet, thighs, and head without letting the ball touch the ground. Start with feet only. Record personal best and beat it each session.", coach_notes:"Encourage players to log their PB — the improvement over a season is remarkable and very motivating." , progression:"Reduce cone spacing to 0.5m. Add a ball — dribble through cones using only the weaker foot." },
  { id:52, title:"Reaction Ball Sprints",        category:"Strength & Conditioning", age_groups:["U12","U13"],       duration:"10 min", players:"Any",                home_ready:false, diagram:"reaction",    description:"Coach holds a cone above their head. On the drop, player sprints forward 10m from a standing start. Vary the direction to work on first-step reactions.", coach_notes:"Focus on the first 3 steps — this is where football acceleration is won or lost." , progression:"Add a ball — dribble in a figure eight pattern. Increase to 15 eights per set." },
  { id:53, title:"Plyometric Box Jumps",         category:"Strength & Conditioning", age_groups:["U13","U14"],       duration:"10 min", players:"Any",                home_ready:false, diagram:"plyo",        description:"Box jumps onto a 30cm platform, stepping off, resetting, repeating. 3 sets of 8 reps, 60s rest between sets.", coach_notes:"Only at U13+. Land softly — absorb the impact through the knees, not the floor." , progression:"Add a 5m sprint immediately after each core exercise before the rest period." },
  { id:54, title:"Speed Gate Runs",              category:"Strength & Conditioning", age_groups:["U12","U13"],       duration:"10 min", players:"Any",                home_ready:false, diagram:"speedgates",  description:"4 speed gates in a T-shape. Players complete timed runs through different gate combinations. Record times and beat them.", coach_notes:"Players push hardest when they have a time to beat. Pair similar-paced players." , progression:"Add a ball — receive a pass, control, then complete the warm-up movement before returning it." },
  { id:55, title:"Interval Shuttle Run",         category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"10 min", players:"Any",                home_ready:false, diagram:"shuttle",     description:"Cones at 5m, 10m, 15m. Sprint to 5m back, 10m back, 15m back — that's one rep. 6 reps, 60s rest between each.", coach_notes:"Monitor effort at U12, not time. By U14 introduce a target time to beat." , progression:"Increase to 45 seconds on, 15 seconds rest. Add a stability challenge — single leg tap." },

  // ── AGE GROUP CHANGES — FAW 2025-26 ──────────────────────────────────────
  { id:56, title:"U11 to U12: Moving to 9v9",        category:"Age Group Changes", age_groups:["U12"],             duration:"10 min", players:"Full squad", home_ready:false, diagram:"9v9",       description:"The step from 7v7 festivals to 9v9 is the biggest change in youth football. Key differences: pitch grows to 64x44 yards, goals 7x16ft, ball size 4, offside rule introduced, a qualified referee controls matches, results count, home and away fixtures replace festivals. Season must start with a non-competitive block before competition begins. Max 18 players per squad. Max 24 competitive weeks per season.", coach_notes:"Walk through offside visually before the season — line players up and show it slowly. Introduce basic positional shape but keep it simple. Season must start non-competitive. Team roster on COMET is compulsory." , progression:"Add directional variation — sprint diagonally to different gates rather than straight ahead." },
  { id:57, title:"U12: 9v9 Rules & Regulations",     category:"Age Group Changes", age_groups:["U12"],             duration:"10 min", players:"Full squad", home_ready:false, diagram:"positions", description:"U12 play 9v9 on a 64x44 yard pitch. 70 minutes (2x35 min halves). Penalty spot 9 yards from goal. Goals 7x16ft. Offside applies. Max 18 players per squad. Goal difference CANNOT be used in league standings. Mercy rule is mandatory — if a team leads by 8 goals, the match is declared over. Goalkeeper cannot pick up a back pass from a teammate. Retreat line — opposition 10 yards from goalkeeper.", coach_notes:"Key FAW rules: no goal difference in standings, mercy rule at 8-goal lead, 50% playing time for all squad members, COMET team roster compulsory. GK cannot handle back passes." , progression:"Increase box height to 40cm. Add a lateral component — jump side to side over the box." },
  { id:58, title:"U12: Offside Rule Explained",       category:"Age Group Changes", age_groups:["U12"],             duration:"10 min", players:"Full squad", home_ready:false, diagram:"offside",   description:"Offside is introduced at U12 for the first time. A player is offside if they are in the opposition half, nearer to the goal than both the ball AND the second-last defender, and involved in active play when the ball is played. Key points: you cannot be offside from a goal kick, throw-in, or corner. Being level with the last defender is NOT offside.", coach_notes:"Make it visual, not verbal — line players up and walk through scenarios slowly. Common mistake: players thinking being in the opposition half alone is offside. Repeat until it clicks." , progression:"Add a ball — dribble to each gate and pass through rather than just running." },
  { id:59, title:"U12: Heading Guidelines",           category:"Age Group Changes", age_groups:["U12"],             duration:"10 min", players:"Full squad", home_ready:false, diagram:"tackle",    description:"FAW 2025-26: Heading is a LOW PRIORITY at U12. When introducing heading technique, the FAW advise: maximum 10 minutes per session, maximum 4 headers per bout, self-serve over short distances only, always use age-appropriate ball at correct pressure. Heading practice must not form any significant part of training. Coaches should encourage a style of play that limits long balls in the air.", coach_notes:"This is FAW guidance for U12 — keep heading minimal and always self-serve. Concussion protocol: any suspected head injury = immediate removal, cannot return to play, parent/guardian advised to seek medical advice. Return only after day 21 if symptom-free for 14 days." , progression:"Add a 10m sprint immediately after each shuttle rep before the rest period." },
  { id:60, title:"U12: Positive Match Day Culture",   category:"Age Group Changes", age_groups:["U12"],             duration:"10 min", players:"Full squad", home_ready:false, diagram:"leadership",description:"FAW mandatory match day rules: (1) All squad members must play minimum 50% of total available playing time. (2) Rolling substitutes — players can re-enter after being substituted. (3) Buffer zone of 2 metres from both touchlines is required. (4) Smoking and vaping is banned from the sideline. (5) Spectators must applaud both teams — no shouting instructions. (6) Coaches must not continually shout instructions during matches.", coach_notes:"Plan substitutions in advance. The 2m buffer zone and smoking ban are enforceable FAW rules. No squad player should sit on the bench for the full match — 50% playing time is mandatory, not a target." , progression:"Add a ball — receive a pass before each shuttle and carry it throughout." },
  { id:61, title:"U12 to U13: Pitch Gets Larger",     category:"Age Group Changes", age_groups:["U12","U13"],       duration:"10 min", players:"Full squad", home_ready:false, diagram:"9v9",       description:"When moving from U12 to U13, the pitch length increases from 64 yards to 76 yards (width 44-54 yards). This is significant — it demands better fitness and faster switching of play. All other U12 rules remain the same. Single age band U13 leagues can operate a fully competitive season. From 1st March, non-competitive 11v11 friendly fixtures can be offered to prepare players for U14.", coach_notes:"Work on fitness and width during U12 to prepare for the larger U13 pitch. From March at U13, organise 11v11 friendlies so players experience the full-size game before moving up." , progression:"Introduce a passive defender to add light pressure to the 7v7 shape." },
  { id:62, title:"U13: Full Competition Rules",        category:"Age Group Changes", age_groups:["U13"],             duration:"10 min", players:"Full squad", home_ready:false, diagram:"positions", description:"U13 is 9v9 on a 76x44-54 yard pitch. 70 minutes (2x35 min halves). Fully competitive for single age band leagues. Goal difference still not permitted in league standings. Mercy rule (8-goal margin) still mandatory. From 1st March, non-competitive 11v11 friendlies can be organised to bridge the gap to U14.", coach_notes:"No goal difference in standings. Mercy rule at 8 goals still applies. Use 11v11 friendlies from March to introduce full positional shape, set pieces, and the larger pitch." , progression:"Run a combined U12/U13 session to expose younger players to the larger 9v9 pitch." },
  { id:63, title:"U13 to U14: Moving to 11v11",        category:"Age Group Changes", age_groups:["U13","U14"],       duration:"10 min", players:"Full squad", home_ready:false, diagram:"positions", description:"U14 is the first age group to play full 11v11 football. Key changes: full-size pitch, size 5 ball, 70-minute matches (2x35 min halves), full IFAB Laws of the Game apply. Players aged 13 on 31st August are eligible. Match day squad 16-18 players (set by Area Association). Fully competitive season. Heading guidelines continue — limit aerial play where possible.", coach_notes:"Prepare players for this during U13 — use the 11v11 friendlies from March. Introduce full positional shape, pressing, and set pieces before the season starts. FAW: 50% playing time still mandatory." , progression:"Add a full offside trap — back 4 step up simultaneously on a verbal trigger." },
  { id:64, title:"U14 to U15: Match Duration Increases",category:"Age Group Changes", age_groups:["U14","U15"],     duration:"10 min", players:"Full squad", home_ready:false, diagram:"tactical",  description:"U15 increases match duration to 80 minutes (2x40 min halves) — up from 70 minutes at U14. Still 11v11, size 5 ball. Players aged 15 on 31st August are eligible for U15 and U16. Mercy rule (8-goal margin) still applies. Rolling substitutes continue. 50% playing time rule still applies.", coach_notes:"The extra 10 minutes increases physical demands. Build stamina work into training from U14. Tactical awareness and set piece organisation become increasingly important at U15." , progression:"Progress to live offside scenarios with active defenders and game speed movement." },
  { id:65, title:"FAW Coach Qualifications & DBS",     category:"Age Group Changes", age_groups:["U12","U13","U14","U15"], duration:"10 min", players:"Full squad", home_ready:false, diagram:"leadership",description:"FAW requirements for all coaches: (1) Minimum FAW Football Leaders Award required. (2) Valid FAW-approved Enhanced DBS Check for Regulated Activity — mandatory for all coaches. (3) FAW First Aid Award required. Coach to player ratios: U9-U12: 1 qualified coach per 16 players, 1 DBS adult per 8 players. U13-U17: 1 qualified coach per 18 players, 1 DBS adult per 10 players. Minimum 2 supervisors always recommended.", coach_notes:"Ensure all coaches have current DBS checks — these must be FAW-approved Enhanced checks for Regulated Activity. First aid qualification required at every training session and match. Review annually." , progression:"Introduce a structured 4-3-3 pressing shape with defined triggers for each position." },
  // ── GOALKEEPING (10) ──────────────────────────────────────────────────────
  { id:66, title:"GK Handling & Distribution",   category:"Goalkeeping", age_groups:["U12","U13","U14"], duration:"10 min", players:"1 GK + server", home_ready:false, diagram:"default", description:"GK receives serves at different heights -- rolled, waist height, high. Catches cleanly then distributes by roll, throw or kick. 5 reps of each type.", coach_notes:"Emphasise getting behind the ball. Hands together, elbows in. Distribute quickly after the catch -- don't hold the ball.", progression:"Add a second server from a different angle. GK must decide which type of distribution is appropriate after each save." },
  { id:67, title:"GK Footwork & Positioning",    category:"Goalkeeping", age_groups:["U12","U13"],       duration:"10 min", players:"1 GK",          home_ready:true,  diagram:"default", description:"Set up 3 cones across the goal line. GK side-steps between them maintaining a low ready stance, staying on their toes throughout. 4 sets of 30 seconds.", coach_notes:"Feet shoulder-width apart, slight forward lean, weight on toes. No crossing of feet -- side-step only.", progression:"Add a ball serve on coach's signal mid-movement -- GK must react and catch without resetting." },
  { id:68, title:"GK Angle Play",                category:"Goalkeeping", age_groups:["U12","U13","U14"], duration:"10 min", players:"1 GK + 3 shooters", home_ready:false, diagram:"default", description:"Shooters take turns shooting from 3 different positions (centre, left, right of the area). GK must move off the line to cut the angle before each shot.", coach_notes:"GK should move forward and across to the near post side. 'Shrink the target' is the key phrase.", progression:"Add a dribble before the shot so GK must react to movement, not just a static ball." },
  { id:69, title:"GK Crosses & Claiming",        category:"Goalkeeping", age_groups:["U13","U14"],       duration:"10 min", players:"1 GK + crosser", home_ready:false, diagram:"cross", description:"Wide player delivers crosses from the left and right. GK must decide to come and claim or stay on the line. Call 'keeper' loudly when coming. 8 crosses each side.", coach_notes:"Decision-making is the skill -- not every cross should be claimed. Call early and be decisive. One missed call = stay.", progression:"Add a passive attacker in the box to challenge the GK on the cross." },
  { id:70, title:"GK Reaction Saves",            category:"Goalkeeping", age_groups:["U12","U13","U14"], duration:"10 min", players:"1 GK + shooter", home_ready:false, diagram:"default", description:"GK starts on their knees at the centre of the goal. Server shoots low to either side from 8m. GK must scramble and react. 10 reps each side.", coach_notes:"This builds recovery speed and reactions. Praise effort over technique here -- it's meant to be hard.", progression:"Serve from 6m to reduce reaction time. Add a second serve immediately after the first to test recovery." },
  { id:71, title:"GK 1v1 Narrowing",             category:"Goalkeeping", age_groups:["U12","U13"],       duration:"10 min", players:"1 GK + attacker", home_ready:false, diagram:"default", description:"Attacker starts 20m from goal and drives towards goal in a 1v1. GK must advance to narrow the angle and decide when to commit. Rotate attackers every 3 reps.", coach_notes:"GK should come to the edge of the penalty area and set early. Spread the body when the attacker gets close. Don't dive early.", progression:"Give attacker a wider starting position so GK must adjust their angle of approach before setting." },
  { id:72, title:"GK Distribution Accuracy",     category:"Goalkeeping", age_groups:["U12","U13","U14"], duration:"10 min", players:"1 GK + targets",  home_ready:true,  diagram:"default", description:"Set 3 targets at different distances (5m, 10m, 20m). GK practises rolling to 5m, throwing overarm to 10m, and kicking to 20m. 5 reps each.", coach_notes:"Accuracy before distance. A bad goal kick that lands with the opposition is worse than a short accurate one.", progression:"Add a receive-and-return element -- the target passes back for GK to catch and redistribute immediately." },
  { id:73, title:"GK Low Dive Technique",        category:"Goalkeeping", age_groups:["U12","U13"],       duration:"10 min", players:"1 GK + server",  home_ready:false, diagram:"default", description:"Server rolls ball firmly to either side of the GK from 8m. GK dives low, collects in two hands, and recovers to feet before next serve. Rest 10s between dives.", coach_notes:"Lead with the bottom hand, top hand on top of the ball. Get body behind the ball -- don't just reach out.", progression:"Serve alternating sides so GK cannot anticipate direction. Increase pace gradually." },
  { id:74, title:"GK Set Piece Positioning",     category:"Goalkeeping", age_groups:["U13","U14"],       duration:"10 min", players:"Full squad",      home_ready:false, diagram:"setpiece", description:"Walk through GK positioning for corners (near post, 2-3 steps off line), free kicks at different angles, and penalty positioning. Static first, then with movement.", coach_notes:"GK should own their area verbally -- organising defenders is part of the role. Encourage shouting names early.", progression:"Run live set pieces with GK organising defenders using real instructions." },
  { id:75, title:"GK Penalty Technique",         category:"Goalkeeping", age_groups:["U13","U14"],       duration:"10 min", players:"1 GK + penalty taker", home_ready:false, diagram:"default", description:"5 penalty takers each take 3 penalties. GK focuses on staying central, staying tall, and moving at the last possible moment. Log save success.", coach_notes:"Don't over-coach the dive direction -- teach patience. The best GKs at this age stay big and wait for the kick.", progression:"Have penalty takers shoot to a called side to practice moving quickly to a pre-decided corner." },

  // ── FROM GRASSROOTS FOOTBALL UK VOL.1 ─────────────────────────────────────

  // S&C / Pre-Season (76-78)
  { id:76, title:"Dirty Dozen / Sickly Six",        category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"20 min", players:"Full squad", home_ready:false, diagram:"shuttle", description:"Split squad into groups by fitness level. Each player completes 12 full-pitch sprints (or 6 for Sickly Six). After each sprint, 10 reps of a different exercise -- star jumps, sit-ups, press-ups, squats, lunges, burpees, tuck jumps etc. Record times each week and stagger starts in Week 2 based on Week 1 gaps.", coach_notes:"Equalises competition -- slower players get head starts in later weeks so everyone is racing against each other. Great for building team culture.", progression:"Reduce recovery between exercises. Add a ball -- dribble the pitch length instead of sprinting." },
  { id:77, title:"S.M.L -- Short Medium Long Sprints", category:"Strength & Conditioning", age_groups:["U12","U13","U14"], duration:"15 min", players:"Full squad", home_ready:false, diagram:"shuttle", description:"Set 3 markers: S = quarter pitch, M = halfway, L = full length. Write S, M, L on paper slips and put in a bag. Each player picks a slip to build the session's sprint sequence. Kids love the tension of the draw. Run 3-5 sets.", coach_notes:"The element of chance makes it fun and removes any sense of the coach making it deliberately hard. Players buy in immediately.", progression:"Add a ball -- the sprint becomes a dribble. Players must arrive at the cone under control." },
  { id:78, title:"Escape Room Ball Mastery",          category:"Strength & Conditioning", age_groups:["U12","U13"],       duration:"10 min", players:"6-12",         home_ready:true,  diagram:"default", description:"Set up a circle with cones. One player starts inside with a ball and must dribble out past the circle boundary. Players on the outside try to kick the ball back in whenever it gets close. If the player escapes, they swap with whoever kicked it last.", coach_notes:"Brilliant warm-up game -- high energy, lots of touches, natural pressing practice without calling it that.", progression:"Add a second ball and second player inside. Reduce circle size." },

  // Passing (79-85)
  { id:79, title:"Zig Zag Passing Race",              category:"Passing",                  age_groups:["U12","U13","U14"], duration:"10 min", players:"8-16",         home_ready:false, diagram:"gates", description:"Set flat discs 10-15 yards apart in a zig-zag line with a player on each. Ball starts at one end. Players pass to the next in the zig-zag, following their pass to the next cone. Time how long it takes to reach the end and back. Challenge the group to beat their time each week.", coach_notes:"Urgency and accuracy are both tested. Players learn to lead the target, pass into space, and move quickly after passing.", progression:"One touch only. Add a second ball starting from the opposite end simultaneously." },
  { id:80, title:"Beat the Clock Rondo",              category:"Passing",                  age_groups:["U12","U13"],       duration:"10 min", players:"8-14",         home_ready:false, diagram:"rondo", description:"Players form a circle around the coach. The coach times how many passes the group can complete in 60 seconds without losing possession to the coach in the middle. Record the score each week and challenge them to beat it.", coach_notes:"The competitive element drives intensity. Start without a defender then progress. Great for quick decision-making under light pressure.", progression:"Add a second defender. Reduce circle size. Limit to two touches, then one touch." },
  { id:81, title:"Double Rondo Head to Head",         category:"Passing",                  age_groups:["U13","U14"],       duration:"15 min", players:"12-16",        home_ready:false, diagram:"rondo", description:"Two equal groups each form a rondo circle. Players are numbered. When a defender wins the ball in one rondo, they call a number. That numbered player must immediately break into the opposite rondo to defend. The original defender joins that rondo as an outfield player.", coach_notes:"Creates chaos in a positive way -- players must stay alert even when not in possession. Excellent for scanning and awareness.", progression:"Shorten the distance between the two circles. Add a time limit -- defender must win ball within 8 seconds." },
  { id:82, title:"Split the Defence Passing",         category:"Passing",                  age_groups:["U12","U13","U14"], duration:"10 min", players:"8-12",         home_ready:false, diagram:"lanes", description:"Divide pitch into 3 zones with 2 defenders positioned between zones. Attackers must pass through each zone to reach the end. If a defender intercepts, teams swap. Encourages finding gaps, weight of pass, and movement off the ball.", coach_notes:"Reinforce that splitting the defence is about timing and disguise -- look one way, pass another. Celebrate the 'through ball'.", progression:"Add a second defender per zone. Reduce zone width to create tighter passing angles." },
  { id:83, title:"Heads Up Pass and Move",            category:"Passing",                  age_groups:["U12","U13"],       duration:"10 min", players:"8-14",         home_ready:false, diagram:"triangle", description:"Players pass and follow in a square or triangle but must call the name of the person they are passing to before they pass. The receiver must acknowledge with eye contact before the ball is played. If no call is made, the pass doesn't count.", coach_notes:"Goes against instinct -- players want to watch the ball. This forces scanning before passing. Massive long-term benefit.", progression:"Add a defender. Require the passer to move to a different position -- not just follow the pass." },
  { id:84, title:"Passing and Control Reactions",     category:"Passing",                  age_groups:["U12","U13","U14"], duration:"10 min", players:"Pairs + coach", home_ready:true,  diagram:"wall", description:"In pairs, Player A passes to Player B who must control and immediately pass to a third target (cone, coach, or another player) called out by the coach at the moment of receiving. Player B must scan before the ball arrives to react quickly enough.", coach_notes:"Simulates real match conditions -- players rarely know where they will pass before they receive. Builds quick decision-making.", progression:"Increase the number of targets to 4. Reduce reaction time by calling the target later." },
  { id:85, title:"Long Pass Switch Play",             category:"Passing",                  age_groups:["U13","U14"],       duration:"10 min", players:"8-12",         home_ready:false, diagram:"switch", description:"Set up in a wide formation. Players must complete 3 short passes before switching the ball with a long diagonal pass to the opposite flank. The receiving player controls and the sequence repeats. Emphasise disguise on the switch ball.", coach_notes:"Long passing is not a hoof -- it is a measured, disguised switch. The preparation and body position before the pass are as important as the pass itself.", progression:"Add a passive defender who can intercept the switch ball. Increase distances gradually." },

  // Attacking (86-87)
  { id:86, title:"Crossing at Pace",                  category:"Attacking",                age_groups:["U13","U14"],       duration:"10 min", players:"6-10",         home_ready:false, diagram:"cross", description:"Wide player starts at halfway, drives at pace toward the byline and crosses into the box. Two strikers make near-post and far-post runs. Cross must be delivered before reaching the goal line. Rotate positions every 4 crosses. Focus on quality of delivery at speed.", coach_notes:"The crossing zone is the area of maximum opportunity -- the closer to the byline, the more the goalkeeper is taken out of the picture. Reinforce this.", progression:"Add a passive defender following the crosser. Vary delivery -- driven low, pulled back, floated far post." },
  { id:87, title:"Short Corner Routines",             category:"Attacking",                age_groups:["U12","U13","U14"], duration:"10 min", players:"5-8",          home_ready:false, diagram:"setpiece", description:"Practice 3 short corner routines using hand signals: Routine 1 -- two-player short with shot from edge of box. Routine 2 -- decoy runner to far post, ball played to unmarked midfielder. Routine 3 -- corner taker receives ball back, drives to create shooting angle. Use a signal system so players recognise which routine is on.", coach_notes:"Short corners work best when they are rehearsed and automatic. Signals must be clear and given early. FAW 9v9 makes corners very impactful -- worth the time.", progression:"Add passive defenders to each routine. Run all 3 routines consecutively without stopping." },

]
